import numpy as np
from collections import Counter

def solve(grid):
    g = np.array(grid)
    H, W = g.shape

    # Step 1: Find outer borders
    outer_borders = find_outer_borders(g)

    # Step 2: For each outer border, find inner rects
    all_pairs = []  # (outer_info, inner_rect_1, inner_rect_2, content_1, content_2)

    for ob in outer_borders:
        inner_rects = find_inner_rects_in_outer(g, ob)
        if len(inner_rects) == 2:
            c1 = get_content(g, inner_rects[0])
            c2 = get_content(g, inner_rects[1])
            all_pairs.append((ob, inner_rects[0], inner_rects[1], c1, c2))

    if len(all_pairs) != 2:
        return grid  # fallback

    # Step 3: Identify KEY pair (neither rect empty) and TARGET pair (one rect empty)
    key_pair = None
    target_pair = None
    for pair in all_pairs:
        ob, ir1, ir2, c1, c2 = pair
        c1_empty = np.all(np.array(c1) == 0)
        c2_empty = np.all(np.array(c2) == 0)
        if c1_empty or c2_empty:
            target_pair = pair
        else:
            key_pair = pair

    if key_pair is None or target_pair is None:
        return grid

    key_ob, key_ir1, key_ir2, key_c1, key_c2 = key_pair
    target_ob, target_ir1, target_ir2, target_c1, target_c2 = target_pair

    key_c1 = np.array(key_c1)
    key_c2 = np.array(key_c2)
    target_c1 = np.array(target_c1)
    target_c2 = np.array(target_c2)

    # Determine which target rect is empty and which has data
    if np.all(target_c1 == 0):
        target_empty = target_c1
        target_given = target_c2
    else:
        target_empty = target_c2
        target_given = target_c1

    # Step 4: Check if KEY pair is complement or subset
    key_c1_nz = key_c1 != 0
    key_c2_nz = key_c2 != 0
    overlap = np.any(key_c1_nz & key_c2_nz)
    union_complete = np.all(key_c1_nz | key_c2_nz)

    if not overlap and union_complete:
        # COMPLEMENT case
        return solve_complement(key_c1, key_c2, target_given)
    else:
        # SUBSET case
        return solve_subset(key_c1, key_c2, target_given)


def solve_complement(key_c1, key_c2, target_given):
    """KEY pair is disjoint/complement. Output = recolored complement of target_given."""
    # Determine which KEY rect corresponds to target_given (same non-zero mask)
    target_mask = target_given != 0
    c1_mask = key_c1 != 0
    c2_mask = key_c2 != 0

    # Check which KEY mask matches target_given mask
    if np.array_equal(c1_mask, target_mask):
        matching_key = key_c1
        other_key = key_c2
    elif np.array_equal(c2_mask, target_mask):
        matching_key = key_c2
        other_key = key_c1
    else:
        # Masks don't match directly - use simple complement
        # Find colors in target_given
        tg_colors = set(int(v) for v in target_given.flatten() if v != 0)
        if len(tg_colors) == 1:
            fill_color = tg_colors.pop()
            output = np.where(target_given == 0, fill_color, 0)
            return output.tolist()
        else:
            # Try to find color mapping without exact mask match
            # Use any non-zero cell correspondence
            matching_key = key_c1  # default
            other_key = key_c2

    # Build color mapping from matching_key to target_given
    color_map = {}
    for r in range(key_c1.shape[0]):
        for c in range(key_c1.shape[1]):
            kv = int(matching_key[r, c])
            tv = int(target_given[r, c])
            if kv != 0 and tv != 0:
                if kv not in color_map:
                    color_map[kv] = tv

    # Apply color mapping to other_key to get output
    output = np.zeros_like(other_key)
    for r in range(other_key.shape[0]):
        for c in range(other_key.shape[1]):
            v = int(other_key[r, c])
            if v != 0:
                output[r, c] = color_map.get(v, v)

    return output.tolist()


def solve_subset(key_c1, key_c2, target_given):
    """KEY pair has subset relationship. Use line-drawing or template."""
    # Determine which is full and which is sparse
    c1_count = np.count_nonzero(key_c1)
    c2_count = np.count_nonzero(key_c2)

    if c1_count >= c2_count:
        key_full = key_c1
        key_sparse = key_c2
    else:
        key_full = key_c2
        key_sparse = key_c1

    # Check if KEY full is symmetric (has any non-trivial symmetry)
    is_symmetric = check_symmetry(key_full)

    if is_symmetric:
        # Use KEY full as template, recolored
        return solve_template(key_full, key_sparse, target_given)
    else:
        # Use line-drawing from target_given markers
        return solve_line_drawing(target_given)


def check_symmetry(arr):
    """Check if array has any non-trivial symmetry."""
    for k in range(1, 4):
        if arr.shape[0] == arr.shape[1] and np.array_equal(arr, np.rot90(arr, k)):
            return True
    if np.array_equal(arr, np.fliplr(arr)):
        return True
    if np.array_equal(arr, np.flipud(arr)):
        return True
    return False


def solve_template(key_full, key_sparse, target_given):
    """Use KEY full pattern as template, recolor for TARGET."""
    # Find non-zero colors in key_full and target_given
    key_colors = {}
    for r in range(key_full.shape[0]):
        for c in range(key_full.shape[1]):
            v = int(key_full[r, c])
            if v != 0:
                if v not in key_colors:
                    key_colors[v] = 0
                key_colors[v] += 1

    target_colors = {}
    for r in range(target_given.shape[0]):
        for c in range(target_given.shape[1]):
            v = int(target_given[r, c])
            if v != 0:
                if v not in target_colors:
                    target_colors[v] = 0
                target_colors[v] += 1

    # Build color mapping by matching roles (fill = most common, edge = less common)
    key_sorted = sorted(key_colors.items(), key=lambda x: -x[1])
    target_sorted = sorted(target_colors.items(), key=lambda x: -x[1])

    color_map = {}
    for i in range(min(len(key_sorted), len(target_sorted))):
        color_map[key_sorted[i][0]] = target_sorted[i][0]

    # Apply color mapping to key_full
    output = np.zeros_like(key_full)
    for r in range(key_full.shape[0]):
        for c in range(key_full.shape[1]):
            v = int(key_full[r, c])
            if v != 0:
                output[r, c] = color_map.get(v, v)

    return output.tolist()


def solve_line_drawing(target_given):
    """Draw lines between markers in target_given."""
    markers = []
    for r in range(target_given.shape[0]):
        for c in range(target_given.shape[1]):
            if target_given[r, c] != 0:
                markers.append((r, c, int(target_given[r, c])))

    # Find the most common non-zero color (fill color)
    colors = [m[2] for m in markers]
    color_counts = Counter(colors)
    fill_color = color_counts.most_common(1)[0][0]

    output = target_given.copy()

    # For each pair of markers sharing a row or column, fill between them
    for i in range(len(markers)):
        for j in range(i+1, len(markers)):
            r1, c1, v1 = markers[i]
            r2, c2, v2 = markers[j]

            if r1 == r2:
                # Same row - fill between them
                cmin, cmax = min(c1, c2), max(c1, c2)
                for c in range(cmin + 1, cmax):
                    if output[r1, c] == 0:
                        output[r1, c] = fill_color
            elif c1 == c2:
                # Same column - fill between them
                rmin, rmax = min(r1, r2), max(r1, r2)
                for r in range(rmin + 1, rmax):
                    if output[r, c1] == 0:
                        output[r, c1] = fill_color

    return output.tolist()


def find_outer_borders(g):
    """Find rectangular borders in the grid."""
    H, W = g.shape
    borders = []

    for color in range(10):
        mask = (g == color)

        # Find rows/cols with high concentration
        row_strong = [r for r in range(H) if mask[r, :].sum() >= W * 0.5]
        col_strong = [c for c in range(W) if mask[:, c].sum() >= H * 0.3]

        if len(row_strong) >= 2:
            r1, r2 = row_strong[0], row_strong[-1]
            if r2 - r1 >= 5:
                # Find left and right columns
                col_data = mask[r1:r2+1, :].sum(axis=0)
                left_col, right_col = -1, -1
                for c in range(W):
                    if col_data[c] >= (r2 - r1 + 1) * 0.7:
                        if left_col == -1:
                            left_col = c
                        right_col = c
                if left_col >= 0 and right_col > left_col:
