import numpy as np
from collections import Counter

def solve(grid):
    g = np.array(grid)
    H, W = g.shape

    def find_outers(g):
        """Find two outer bordered rectangles by looking for colors with long contiguous runs."""
        H, W = g.shape
        candidates = {}

        # Check each color for long horizontal runs
        for c in range(10):
            max_run = 0
            for r in range(H):
                run = 0
                for col in range(W):
                    if g[r, col] == c:
                        run += 1
                        max_run = max(max_run, run)
                    else:
                        run = 0
            # Check vertical runs too
            for col in range(W):
                run = 0
                for r in range(H):
                    if g[r, col] == c:
                        run += 1
                        max_run = max(max_run, run)
                    else:
                        run = 0
            if max_run >= 10:
                candidates[c] = max_run

        outers = []
        for c in sorted(candidates, key=candidates.get, reverse=True):
            # Find bounding box of all cells with color c
            rows, cols = np.where(g == c)
            if len(rows) == 0:
                continue
            r1, r2 = rows.min(), rows.max()
            c1, c2 = cols.min(), cols.max()

            # Shrink to find actual border
            # Top edge: find row where entire row[c1:c2+1] is color c
            top = r1
            while top <= r2:
                if np.all(g[top, c1:c2+1] == c):
                    break
                top += 1

            bottom = r2
            while bottom >= top:
                if np.all(g[bottom, c1:c2+1] == c):
                    break
                bottom -= 1

            left = c1
            while left <= c2:
                if np.all(g[top:bottom+1, left] == c):
                    break
                left += 1

            right = c2
            while right >= left:
                if np.all(g[top:bottom+1, right] == c):
                    break
                right -= 1

            if bottom - top >= 8 and right - left >= 8:
                # Check it forms a border (top/bottom rows, left/right cols are all c)
                ok = (np.all(g[top, left:right+1] == c) and 
                      np.all(g[bottom, left:right+1] == c) and
                      np.all(g[top:bottom+1, left] == c) and
                      np.all(g[top:bottom+1, right] == c))
                if ok:
                    outers.append((c, top, bottom, left, right))

        # Remove duplicates / overlapping
        final = []
        for o in outers:
            overlap = False
            for f in final:
                # Check if o is inside f or vice versa
                if o[1] >= f[1] and o[2] <= f[2] and o[3] >= f[3] and o[4] <= f[4]:
                    overlap = True
                    break
            if not overlap:
                final.append(o)

        return final[:2]  # We expect exactly 2

    def find_inners(g, outer):
        """Find two inner bordered rectangles inside an outer border."""
        oc, ot, ob, ol, orr = outer
        interior = g[ot+1:ob, ol+1:orr]
        ih, iw = interior.shape

        # Find candidate inner border colors
        color_counts = Counter()
        for r in range(ih):
            for c in range(iw):
                if interior[r, c] != oc:
                    color_counts[interior[r, c]] += 1

        best_color = None
        best_rects = None

        for ic in color_counts:
            if ic == 0:
                continue
            # Find rectangular borders of color ic in the interior
            rects = []
            rows, cols = np.where(interior == ic)
            if len(rows) < 8:
                continue

            # Try to find connected rectangular borders
            # Cluster by connectivity
            visited = set()
            clusters = []
            positions = set(zip(rows.tolist(), cols.tolist()))

            for pos in positions:
                if pos in visited:
                    continue
                # BFS
                cluster = []
                queue = [pos]
                visited.add(pos)
                while queue:
                    cr, cc = queue.pop(0)
                    cluster.append((cr, cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if (nr, nc) in positions and (nr, nc) not in visited:
                            visited.add((nr, nc))
                            queue.append((nr, nc))
                clusters.append(cluster)

            for cluster in clusters:
                rs = [p[0] for p in cluster]
                cs = [p[1] for p in cluster]
                r1, r2 = min(rs), max(rs)
                c1, c2 = min(cs), max(cs)

                # Check if forms a rectangular border
                if r2 - r1 < 2 or c2 - c1 < 2:
                    continue

                top_ok = all(interior[r1, c] == ic for c in range(c1, c2+1))
                bot_ok = all(interior[r2, c] == ic for c in range(c1, c2+1))
                left_ok = all(interior[r, c1] == ic for r in range(r1, r2+1))
                right_ok = all(interior[r, c2] == ic for r in range(r1, r2+1))

                if top_ok and bot_ok and left_ok and right_ok:
                    # Extract content (inside the border)
                    content = interior[r1+1:r2, c1+1:c2].copy()
                    # Convert to absolute coordinates
                    abs_r1 = ot + 1 + r1
                    abs_c1 = ol + 1 + c1
                    rects.append((abs_r1, abs_c1, r2-r1-1, c2-c1-1, content))

            if len(rects) == 2:
                # Check matching content sizes
                if rects[0][2] == rects[1][2] and rects[0][3] == rects[1][3]:
                    if best_rects is None or rects[0][2] * rects[0][3] > best_rects[0][2] * best_rects[0][3]:
                        best_color = ic
                        best_rects = rects

        return best_rects

    outers = find_outers(g)

    # Find inner rects for each outer
    all_pairs = []
    for outer in outers:
        inners = find_inners(g, outer)
        if inners:
            all_pairs.append((outer, inners))

    # Identify KEY pair (neither content is all zeros) and TARGET pair (one is all zeros)
    key_pair = None
    target_pair = None

    for outer, inners in all_pairs:
        c1 = inners[0][4]
        c2 = inners[1][4]
        z1 = np.all(c1 == 0)
        z2 = np.all(c2 == 0)
        if not z1 and not z2:
            key_pair = (outer, inners)
        elif z1 or z2:
            target_pair = (outer, inners)

    if key_pair is None or target_pair is None:
        # Fallback: if one pair has both non-zero, it's key; other is target
        for outer, inners in all_pairs:
            c1 = inners[0][4]
            c2 = inners[1][4]
            z1 = np.all(c1 == 0)
            z2 = np.all(c2 == 0)
            if z1 or z2:
                target_pair = (outer, inners)
            else:
                key_pair = (outer, inners)

    key_c1 = key_pair[1][0][4]  # content of first inner rect in key pair
    key_c2 = key_pair[1][1][4]  # content of second inner rect in key pair

    # Identify target_given and target_empty
    t_inners = target_pair[1]
    if np.all(t_inners[0][4] == 0):
        target_empty = t_inners[0][4]
        target_given = t_inners[1][4]
    else:
        target_empty = t_inners[1][4]
        target_given = t_inners[0][4]

    # Check overlap between key pair
    mask1 = key_c1 != 0
    mask2 = key_c2 != 0
    overlap = np.any(mask1 & mask2)

    if not overlap:
        # COMPLEMENT case
        # Check which key rect's mask matches target_given's mask
        target_mask = target_given != 0

        if np.array_equal(mask1, target_mask):
            matching_key = key_c1
            other_key = key_c2
        else:
            matching_key = key_c2
            other_key = key_c1

        # Build color mapping from matching_key to target_given
        color_map = {}
        for r in range(matching_key.shape[0]):
            for c in range(matching_key.shape[1]):
                if matching_key[r, c] != 0:
                    color_map[int(matching_key[r, c])] = int(target_given[r, c])

        # Apply mapping to other_key
        output = np.zeros_like(other_key)
        for r in range(other_key.shape[0]):
            for c in range(other_key.shape[1]):
                v = int(other_key[r, c])
                if v in color_map:
                    output[r, c] = color_map[v]
                else:
                    output[r, c] = v  # keep 0s as 0s

        return output.tolist()
    else:
        # SUBSET case
        # Determine which is "full" (more non-zero) and which is "sparse"
        if np.count_nonzero(key_c1) >= np.count_nonzero(key_c2):
            key_full = key_c1
            key_sparse = key_c2
        else:
            key_full = key_c2
            key_sparse = key_c1

        # Check symmetry of key_full
        def is_symmetric(arr):
            # Check all D4 symmetries
            if np.array_equal(arr, np.flip(arr, 0)):
                return True
            if np.array_equal(arr, np.flip(arr, 1)):
                return True
            if np.array_equal(arr, np.rot90(arr, 1)):
                return True
            if np.array_equal(arr, np.rot90(arr, 2)):
                return True
            return False

        symmetric = is_symmetric(key_full)

        if symmetric:
            # Template + recolor case
            # Find color mapping: shared colors map to themselves
            # Unique colors in key map to unique colors in target
            key_colors = set(int(x) for x in key_full.flat if x != 0)
            sparse_colors = set(int(x) for x in key_sparse.flat if x != 0)
            target_colors = set(int(x) for x in target_given.flat if x != 0)

            # Colors shared between key_full and target_given
            shared = key_colors & target_colors
            key_unique = key_colors - shared
            target_unique = target_colors - shared

            # Build mapping
            color_map = {c: c for c in shared}

            # Map key_unique to target_unique by frequency
            if key_unique and target_unique:
                key_freq = Counter()
                for v in key_full.flat:
                    v = int(v)
                    if v in key_unique:
                        key_freq[v] += 1

                target_freq = Counter()
                for v in target_given.flat:
                    v = int(v)
                    if v in target_unique:
                        target_freq[v] += 1

                # Sort by frequency and pair up
                key_sorted = sorted(key_unique, key=lambda x: key_freq.get(x, 0), reverse=True)
                target_sorted = sorted(target_unique, key=lambda x: target_freq.get(x, 0), reverse=True)

                for k, t in zip(key_sorted, target_sorted):
                    color_map[k] = t

            # Apply mapping to key_full
            output = np.zeros_like(key_full)
            for r in range(key_full.shape[0]):
                for c in range(key_full.shape[1]):
                    v = int(key_full[r, c])
                    if v in color_map:
                        output[r, c] = color_map[v]
                    else:
                        output[r, c] = v

            return output.tolist()
        else:
            # Line-drawing case (asymmetric)
            # Find the fill color (most common non-zero in target_given)
            tc = Counter()
            for v in target_given.flat:
                v = int(v)
                if v != 0:
                    tc[v] += 1
            fill_color = tc.most_common(1)[0][0]

            # Get marker positions
            markers = {}
            for r in range(target_given.shape[0]):
                for c in range(target_given.shape[1]):
                    v = int(target_given[r, c])
                    if v != 0:
                        markers[(r, c)] = v

            output = np.zeros_like(target_given)

            # Place markers
            for (r, c), v in markers.items():
                output[r, c] = v

            # Draw lines between markers sharing rows
            row_markers = {}
            for (r, c), v in markers.items():
                if r not in row_markers:
                    row_markers[r] = []
                row_markers[r].append(c)

            for r, cols_list in row_markers.items():
                if len(cols_list) >= 2:
                    c_min, c_max = min(cols_list), max(cols_list)
                    for c in range(c_min, c_max + 1):
                        if output[r, c] == 0:
                            output[r, c] = fill_color

            # Draw lines between markers sharing columns
            col_markers = {}
            for (r, c), v in markers.items():
                if c not in col_markers:
                    col_markers[c] = []
                col_markers[c].append(r)

            for c, rows_list in col_markers.items():
                if len(rows_list) >= 2:
                    r_min, r_max = min(rows_list), max(rows_list)
                    for r in range(r_min, r_max + 1):
                        if output[r, c] == 0:
                            output[r, c] = fill_color

            return output.tolist()

# Test
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Train {i}: {'PASS' if match else 'FAIL'}")
