def solve(grid):
    import numpy as np
    from collections import Counter

    g = np.array(grid)
    H, W = g.shape

    def find_borders(g):
        H, W = g.shape
        borders = []
        for c in range(1, 10):
            mask = (g == c)
            long_rows = []
            for r in range(H):
                max_run = 0
                run = 0
                for col in range(W):
                    if mask[r, col]:
                        run += 1
                        max_run = max(max_run, run)
                    else:
                        run = 0
                if max_run >= 8:
                    long_rows.append((r, max_run))

            long_cols = []
            for col in range(W):
                max_run = 0
                run = 0
                for r in range(H):
                    if mask[r, col]:
                        run += 1
                        max_run = max(max_run, run)
                    else:
                        run = 0
                if max_run >= 8:
                    long_cols.append((col, max_run))

            if len(long_rows) >= 2 and len(long_cols) >= 2:
                row_indices = sorted([r for r, _ in long_rows])
                col_indices = sorted([col for col, _ in long_cols])
                top, bottom = row_indices[0], row_indices[-1]
                left, right = col_indices[0], col_indices[-1]

                top_ok = all(g[top, col] == c for col in range(left, right+1))
                bot_ok = all(g[bottom, col] == c for col in range(left, right+1))
                left_ok = all(g[r, left] == c for r in range(top, bottom+1))
                right_ok = all(g[r, right] == c for r in range(top, bottom+1))

                if top_ok and bot_ok and left_ok and right_ok and (bottom - top >= 6) and (right - left >= 6):
                    borders.append((c, top, bottom, left, right))

        # Remove contained
        final = []
        for b in borders:
            contained = False
            for b2 in borders:
                if b2 == b: continue
                if b[1] > b2[1] and b[2] < b2[2] and b[3] > b2[3] and b[4] < b2[4]:
                    contained = True
                    break
            if not contained:
                final.append(b)
        return final

    def find_inners(g, outer):
        oc, ot, ob, ol, orr = outer
        interior = g[ot+1:ob, ol+1:orr]
        ih, iw = interior.shape

        color_counts = Counter()
        for r in range(ih):
            for c in range(iw):
                v = int(interior[r, c])
                if v != oc:
                    color_counts[v] += 1

