                    max_r2 = r1
                    while max_r2 + 1 < ih and interior[max_r2 + 1, c1] == ic:
                        max_r2 += 1
                    if max_r2 - r1 < 3: continue

                    max_c2 = c1
                    while max_c2 + 1 < iw and interior[r1, max_c2 + 1] == ic:
                        max_c2 += 1
                    if max_c2 - c1 < 3: continue

                    for r2 in range(r1 + 3, max_r2 + 1):
                        for c2 in range(c1 + 3, max_c2 + 1):
                            top_ok = all(interior[r1, c] == ic for c in range(c1, c2+1))
                            bot_ok = all(interior[r2, c] == ic for c in range(c1, c2+1))
                            left_ok = all(interior[r, c1] == ic for r in range(r1, r2+1))
                            right_ok = all(interior[r, c2] == ic for r in range(r1, r2+1))
                            if top_ok and bot_ok and left_ok and right_ok:
                                rects.append((r1, c1, r2, c2))

            # Keep maximal
            maximal = []
            for i, rect in enumerate(rects):
                is_sub = False
                for j, other in enumerate(rects):
                    if i == j: continue
                    if (rect[0] >= other[0] and rect[1] >= other[1] and 
                        rect[2] <= other[2] and rect[3] <= other[3] and rect != other):
                        is_sub = True
                        break
                if not is_sub:
                    maximal.append(rect)

            rect_data = []
            for rect in maximal:
                r1, c1, r2, c2 = rect
                content = interior[r1+1:r2, c1+1:c2].copy()
                if content.shape[0] >= 2 and content.shape[1] >= 2:
                    rect_data.append(content)

            if len(rect_data) == 2:
                if rect_data[0].shape == rect_data[1].shape:
                    results[ic] = rect_data

        if len(results) == 1:
            return list(results.values())[0]
        elif len(results) > 1:
            best = max(results.values(), key=lambda x: x[0].shape[0] * x[0].shape[1])
            return best
        return None

    borders = find_borders(g)

    all_pairs = []
    for outer in borders:
        inners = find_inners(g, outer)
        if inners:
            all_pairs.append(inners)

    # Identify KEY pair and TARGET pair
    key_pair = None
    target_pair = None

    for inners in all_pairs:
        c1, c2 = inners[0], inners[1]
        z1 = np.all(c1 == 0)
        z2 = np.all(c2 == 0)
        if not z1 and not z2:
            key_pair = inners
        elif z1 or z2:
