                    borders.append((c, top, bottom, left, right))
        final = []
        for b in borders:
            if not any(b != b2 and b[1] > b2[1] and b[2] < b2[2] and b[3] > b2[3] and b[4] < b2[4] for b2 in borders):
                final.append(b)
        return final

    def find_inners(g, outer):
        oc, ot, ob, ol, orr = outer
        interior = g[ot+1:ob, ol+1:orr]
        ih, iw = interior.shape

        color_counts = Counter(int(interior[r, c]) for r in range(ih) for c in range(iw) if interior[r, c] != oc)
        results = {}

        for ic in color_counts:
            if ic == 0: continue
            rects = []
            for r1 in range(ih - 3):
                for c1 in range(iw - 3):
                    if interior[r1, c1] != ic: continue
                    max_r2 = r1
                    while max_r2 + 1 < ih and interior[max_r2 + 1, c1] == ic: max_r2 += 1
                    if max_r2 - r1 < 3: continue
                    max_c2 = c1
                    while max_c2 + 1 < iw and interior[r1, max_c2 + 1] == ic: max_c2 += 1
                    if max_c2 - c1 < 3: continue
                    for r2 in range(r1 + 3, max_r2 + 1):
                        for c2 in range(c1 + 3, max_c2 + 1):
                            if (all(interior[r1, c] == ic for c in range(c1, c2+1)) and
                                all(interior[r2, c] == ic for c in range(c1, c2+1)) and
                                all(interior[r, c1] == ic for r in range(r1, r2+1)) and
                                all(interior[r, c2] == ic for r in range(r1, r2+1))):
                                rects.append((r1, c1, r2, c2))
            maximal = [r for i, r in enumerate(rects) if not any(
                i != j and r[0] >= o[0] and r[1] >= o[1] and r[2] <= o[2] and r[3] <= o[3] and r != o
                for j, o in enumerate(rects))]
            rect_data = []
            for rect in maximal:
                r1, c1, r2, c2 = rect
                content = interior[r1+1:r2, c1+1:c2].copy()
                if content.shape[0] >= 2 and content.shape[1] >= 2:
                    rect_data.append(content)
            if len(rect_data) == 2 and rect_data[0].shape == rect_data[1].shape:
                results[ic] = rect_data

        if len(results) == 1: return list(results.values())[0]
        if len(results) > 1: return max(results.values(), key=lambda x: x[0].size)
        return None

    borders = find_borders(g)
    all_pairs = []
    for outer in borders:
        inners = find_inners(g, outer)
        if inners: all_pairs.append(inners)

    key_pair = target_pair = None
    for inners in all_pairs:
        if np.all(inners[0] == 0) or np.all(inners[1] == 0):
            target_pair = inners
        else:
            key_pair = inners

    key_c1, key_c2 = key_pair
    target_given = target_pair[1] if np.all(target_pair[0] == 0) else target_pair[0]

    mask1, mask2 = key_c1 != 0, key_c2 != 0
    overlap = np.any(mask1 & mask2)

    if not overlap:
        # COMPLEMENT
        target_mask = target_given != 0

        if np.array_equal(mask1, target_mask):
            matching_key, other_key = key_c1, key_c2
        elif np.array_equal(mask2, target_mask):
            matching_key, other_key = key_c2, key_c1
        else:
            matching_key = None

        if matching_key is not None:
            color_map = {}
            for r in range(matching_key.shape[0]):
                for c in range(matching_key.shape[1]):
                    if matching_key[r, c] != 0:
                        color_map[int(matching_key[r, c])] = int(target_given[r, c])
            output = np.zeros_like(other_key)
            for r in range(other_key.shape[0]):
                for c in range(other_key.shape[1]):
                    v = int(other_key[r, c])
                    if v in color_map: output[r, c] = color_map[v]
            return output.tolist()
        else:
            colors = set(int(x) for x in target_given.flat if x != 0)
            fill_color = list(colors)[0] if len(colors) == 1 else max(colors, key=lambda c: np.count_nonzero(target_given == c))
            output = np.where(~target_mask, fill_color, 0)
            return output.tolist()

    else:
        # SUBSET
        if np.count_nonzero(key_c1) >= np.count_nonzero(key_c2):
            key_full, key_sparse = key_c1, key_c2
        else:
            key_full, key_sparse = key_c2, key_c1

        def is_symmetric(arr):
            for k in range(1, 4):
                if arr.shape[0] == arr.shape[1] and np.array_equal(arr, np.rot90(arr, k)): return True
            if np.array_equal(arr, np.flip(arr, 0)): return True
            if np.array_equal(arr, np.flip(arr, 1)): return True
            return False

        if is_symmetric(key_full):
            key_colors = set(int(x) for x in key_full.flat if x != 0)
            target_colors = set(int(x) for x in target_given.flat if x != 0)
            shared = key_colors & target_colors
            key_unique = key_colors - shared
            target_unique = target_colors - shared

            color_map = {c: c for c in shared}
            if key_unique and target_unique:
                kf = Counter(int(v) for v in key_full.flat if int(v) in key_unique)
                tf = Counter(int(v) for v in target_given.flat if int(v) in target_unique)
                for k, t in zip(sorted(key_unique, key=lambda x: kf.get(x,0), reverse=True),
                                sorted(target_unique, key=lambda x: tf.get(x,0), reverse=True)):
                    color_map[k] = t

            output = np.zeros_like(key_full)
            for r in range(key_full.shape[0]):
                for c in range(key_full.shape[1]):
                    v = int(key_full[r, c])
                    output[r, c] = color_map.get(v, v)
            return output.tolist()
        else:
            tc = Counter(int(v) for v in target_given.flat if v != 0)
            fill_color = tc.most_common(1)[0][0]

            markers = {}
            for r in range(target_given.shape[0]):
                for c in range(target_given.shape[1]):
                    v = int(target_given[r, c])
                    if v != 0: markers[(r, c)] = v

            output = np.zeros_like(target_given)
            for (r, c), v in markers.items(): output[r, c] = v

            row_m, col_m = {}, {}
            for (r, c) in markers:
                row_m.setdefault(r, []).append(c)
                col_m.setdefault(c, []).append(r)

            for r, cs in row_m.items():
                if len(cs) >= 2:
                    for c in range(min(cs), max(cs)+1):
                        if output[r, c] == 0: output[r, c] = fill_color
            for c, rs in col_m.items():
                if len(rs) >= 2:
                    for r in range(min(rs), max(rs)+1):
                        if output[r, c] == 0: output[r, c] = fill_color

            return output.tolist()

```

